tle button{border:0;background:none;color:#d98d00;cursor:pointer}.studio-forum-shell aside>button{display:flex;width:100%;align-items:center;gap:10px;padding:11px;border:0;border-radius:11px;background:none;text-align:left;cursor:pointer}.studio-forum-shell aside>button:hover,.studio-forum-shell aside>button.active{background:#fff6dc}.studio-forum-shell aside>button>span{display:grid;width:35px;height:35px;place-items:center;border-radius:10px;background:#172033;color:#fec433;font-weight:800}.studio-forum-shell aside>button div{display:grid}.studio-forum-shell aside small{color:#98a2b3}.topic-head{display:flex;justify-content:space-between;color:#d98d00}.topic-head button{border:0;background:none;cursor:pointer}.topic-dialog article{padding:16px 8px 30px;border-bottom:1px solid #edf0f5}.topic-dialog article h1{font-size:29px}.author{display:flex;gap:10px}.author img,.replies img{width:40px;height:40px;border-radius:50%}.author span{display:grid}.author small,.replies small{color:#98a2b3}.topic-dialog article>p{min-height:120px;margin-top:28px;white-space:pre-wrap;line-height:1.9}.replies{padding:20px 8px}.replies h2 small{color:#d98d00}.replies>div{display:flex;gap:12px;padding:17px 0;border-bottom:1px solid #edf0f5}.replies>div>span{display:grid;flex:1}.replies p{white-space:pre-wrap}.reply-box{display:grid!important;gap:10px!important;padding:18px!important;border:1px solid #f0dfb4!important;border-radius:14px;background:#fffaf0}@media(max-width:800px){.studio-forum-shell>main{grid-template-columns:1fr}.studio-forum-shell aside{order:-1}.toolbar{flex-direction:column}.toolbar .el-select{width:100%}}
</style>
